import{_ as a,o as t,c as n,ae as s}from"./chunks/framework.D8e0q88G.js";const m=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md"}'),o={name:"architecture.md"};function r(i,e,d,l,c,p){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><h2 id="system-overview" tabindex="-1">System Overview <a class="header-anchor" href="#system-overview" aria-label="Permalink to &quot;System Overview&quot;">​</a></h2><p>SprintLab is split into two independent processes — a React single-page app in the browser and a Python FastAPI server running locally. They communicate over HTTP: the frontend POSTs a video file and the backend streams results back as <a href="https://developer.mozilla.org/en-US/docs/Web/API/Server-sent_events/Using_server-sent_events" target="_blank" rel="noreferrer">Server-Sent Events</a>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Browser (React SPA)                                        │</span></span>
<span class="line"><span>│                                                             │</span></span>
<span class="line"><span>│  ┌──────────────┐   ┌──────────────┐   ┌───────────────┐   │</span></span>
<span class="line"><span>│  │   Viewport   │   │  Telemetry   │   │  VideoContext │   │</span></span>
<span class="line"><span>│  │  overlays,   │   │  sparklines, │   │  shared state │   │</span></span>
<span class="line"><span>│  │  pose, calib │   │  contacts    │   │  + metrics    │   │</span></span>
<span class="line"><span>│  └──────┬───────┘   └──────┬───────┘   └──────┬────────┘   │</span></span>
<span class="line"><span>│         │                  │                   │            │</span></span>
<span class="line"><span>│         └──────────────────┴───────────────────┘            │</span></span>
<span class="line"><span>│                            │                                │</span></span>
<span class="line"><span>│                 useSprintMetrics (hook)                      │</span></span>
<span class="line"><span>│                      sprintMath.ts (pure)                   │</span></span>
<span class="line"><span>│                            │                                │</span></span>
<span class="line"><span>│              POST /infer/video  ←→  SSE stream              │</span></span>
<span class="line"><span>└────────────────────────────┼────────────────────────────────┘</span></span>
<span class="line"><span>                             │</span></span>
<span class="line"><span>┌────────────────────────────▼────────────────────────────────┐</span></span>
<span class="line"><span>│  Backend (FastAPI, localhost:8080)                          │</span></span>
<span class="line"><span>│                                                             │</span></span>
<span class="line"><span>│  GET  /health          readiness probe                      │</span></span>
<span class="line"><span>│  POST /infer/video     SSE: progress events + result        │</span></span>
<span class="line"><span>│                                                             │</span></span>
<span class="line"><span>│  OpenCV → frame extraction                                  │</span></span>
<span class="line"><span>│  RTMLib Wholebody3d → 133 keypoints per frame               │</span></span>
<span class="line"><span>│  ONNX Runtime → CPU inference                               │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="data-flow" tabindex="-1">Data Flow <a class="header-anchor" href="#data-flow" aria-label="Permalink to &quot;Data Flow&quot;">​</a></h2><h3 id="_1-upload-→-inference" tabindex="-1">1. Upload → Inference <a class="header-anchor" href="#_1-upload-→-inference" aria-label="Permalink to &quot;1. Upload → Inference&quot;">​</a></h3><p>The user uploads a video. The frontend reads it as a <code>Blob</code> and POSTs it to <code>POST /infer/video</code>. The backend opens the file with OpenCV and runs every frame through RTMLib&#39;s Wholebody3d model.</p><p>Two SSE event types are emitted:</p><table tabindex="0"><thead><tr><th>Event type</th><th>When</th><th>Payload</th></tr></thead><tbody><tr><td><code>progress</code></td><td>After each frame</td><td><code>{ frame, total, pct, fps, elapsed, eta }</code></td></tr><tr><td><code>result</code></td><td>Once, at the end</td><td><code>{ fps, frame_width, frame_height, total_frames, n_kpts, frames }</code></td></tr></tbody></table><p>The frontend shows the <code>progress</code> events in a status bar. When the <code>result</code> event arrives, keypoints are stored in a <code>Map&lt;frameIdx, Keypoint[]&gt;</code> inside <code>VideoContext</code>.</p><h3 id="_2-keypoint-wire-format" tabindex="-1">2. Keypoint Wire Format <a class="header-anchor" href="#_2-keypoint-wire-format" aria-label="Permalink to &quot;2. Keypoint Wire Format&quot;">​</a></h3><p>Each entry in <code>result.frames</code> is a flat <code>number[]</code> of length <code>n_kpts × 6</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[ x0, y0, s0,  x1, y1, s1,  ...  xN, yN, sN,   ← 2D coords + score (n_kpts × 3)</span></span>
<span class="line"><span>  x0, y0, z0,  x1, y1, z1,  ...  xN, yN, zN ]   ← 3D coords (n_kpts × 3)</span></span></code></pre></div><p>The frontend splits at index <code>n_kpts × 3</code> to recover 2D and 3D arrays separately. SprintLab currently uses only the 2D keypoints for all metric computation.</p><h3 id="_3-metrics-computation" tabindex="-1">3. Metrics Computation <a class="header-anchor" href="#_3-metrics-computation" aria-label="Permalink to &quot;3. Metrics Computation&quot;">​</a></h3><p>Once inference finishes, the <code>useSprintMetrics</code> hook runs a single <code>useMemo</code> pass over all frames. The hook:</p><ol><li>Extracts per-landmark point arrays using a confidence threshold (<code>score ≥ 0.35</code>)</li><li>Detects ground contact windows for both feet</li><li>Computes interior joint angles, segment inclinations, and thigh angles for every frame</li><li>Applies box smoothing and central-difference differentiation to produce velocity and acceleration series</li><li>Builds the CoM trajectory and integrates speed to get cumulative distance</li></ol><p>All pure math lives in <a href="/zero/frontend/metrics.html#sprintmathts"><code>sprintMath.ts</code></a> — framework-free TypeScript with no React dependencies.</p><h3 id="_4-rendering" tabindex="-1">4. Rendering <a class="header-anchor" href="#_4-rendering" aria-label="Permalink to &quot;4. Rendering&quot;">​</a></h3><p>The Viewport renders multiple canvas overlays stacked on top of the video element:</p><table tabindex="0"><thead><tr><th>Overlay</th><th>Purpose</th></tr></thead><tbody><tr><td><code>PoseOverlay</code></td><td>Draws the 133-keypoint skeleton on each frame</td></tr><tr><td><code>CalibrationOverlay</code></td><td>Interactive line-drawing tool for pixel-to-metre scaling</td></tr><tr><td><code>MeasurementOverlay</code></td><td>Freehand distance and angle measurements</td></tr><tr><td><code>CropOverlay</code></td><td>Box selection for video crop</td></tr></tbody></table><p>The Telemetry panel reads from <code>VideoContext</code> and renders sparklines. A playhead drawn inside each sparkline tracks the current video frame.</p><h2 id="state-management" tabindex="-1">State Management <a class="header-anchor" href="#state-management" aria-label="Permalink to &quot;State Management&quot;">​</a></h2><p>SprintLab uses two React Contexts rather than a global state library:</p><h3 id="videocontext" tabindex="-1"><code>VideoContext</code> <a class="header-anchor" href="#videocontext" aria-label="Permalink to &quot;\`VideoContext\`&quot;">​</a></h3><p>The central store. Holds:</p><ul><li>Video metadata (fps, total frames, frame dimensions)</li><li>Current frame index</li><li>Calibration data (<code>pixelsPerMeter</code>, <code>aspectRatio</code>)</li><li>Computed <code>SprintMetrics</code> (output of <code>useSprintMetrics</code>)</li><li>Ground contact events (detected + manually added)</li><li>Sprint markers (start frame, finish frame, mode)</li></ul><h3 id="posecontext" tabindex="-1"><code>PoseContext</code> <a class="header-anchor" href="#posecontext" aria-label="Permalink to &quot;\`PoseContext\`&quot;">​</a></h3><p>A minimal context for pose processing status: <code>idle | loading | ready | error</code>. Used by the Telemetry panel to decide what empty state to display.</p><h3 id="why-two-contexts" tabindex="-1">Why two contexts? <a class="header-anchor" href="#why-two-contexts" aria-label="Permalink to &quot;Why two contexts?&quot;">​</a></h3><p><code>VideoContext</code> is large — it covers video state, calibration, and metrics all in one place to avoid deeply nested prop drilling. <code>PoseContext</code> is kept separate because its state is only relevant to a small number of components and changes at a different lifecycle (only during inference).</p><h2 id="design-decisions" tabindex="-1">Design Decisions <a class="header-anchor" href="#design-decisions" aria-label="Permalink to &quot;Design Decisions&quot;">​</a></h2><h3 id="sse-instead-of-websockets" tabindex="-1">SSE instead of WebSockets <a class="header-anchor" href="#sse-instead-of-websockets" aria-label="Permalink to &quot;SSE instead of WebSockets&quot;">​</a></h3><p>Inference is a one-way push: the backend sends data, the frontend only receives. SSE is simpler and more appropriate than WebSockets for this pattern — it uses plain HTTP, works through proxies, and reconnects automatically.</p><h3 id="client-side-video-processing" tabindex="-1">Client-side video processing <a class="header-anchor" href="#client-side-video-processing" aria-label="Permalink to &quot;Client-side video processing&quot;">​</a></h3><p>Video trimming, cropping, and export use FFmpeg.js (compiled to WebAssembly). This means no video data is sent to any server for those operations — the entire editing pipeline runs in the browser. This is both faster (no upload round-trip) and more privacy-preserving.</p><h3 id="pure-math-layer" tabindex="-1">Pure math layer <a class="header-anchor" href="#pure-math-layer" aria-label="Permalink to &quot;Pure math layer&quot;">​</a></h3><p>All biomechanics computation is extracted into <code>sprintMath.ts</code> — a file with zero React dependencies. This makes the math fully unit-testable with Vitest without any DOM or component setup. See the <a href="/zero/math.html">Math Reference</a> for the full equations.</p><h3 id="confidence-thresholding" tabindex="-1">Confidence thresholding <a class="header-anchor" href="#confidence-thresholding" aria-label="Permalink to &quot;Confidence thresholding&quot;">​</a></h3><p>Keypoints with a score below <code>0.35</code> are treated as <code>null</code>. Null gaps in time series are forward-filled then backward-filled before smoothing, so a briefly occluded joint doesn&#39;t break the derivative chain.</p>`,40)])])}const u=a(o,[["render",r]]);export{m as __pageData,u as default};
